import { FormMode } from '../../../../../components/form';
import {
  CASH_VOUCHER_DISPLAY_ONLY_HEADER_KEYS,
  defaultCashVoucherHeader,
} from '../types/cashVoucherHeader.types';
import type { CashVoucherFormAction, CashVoucherFormReducerState } from '../types/cashVoucherFormState.types';
import { emptyCashVoucherLine, type CashVoucherLineModel } from '../types/cashVoucherLine.types';
import {
  initHeaderFields,
  initLineFields,
  newLineId,
  setFieldError,
  setFieldValue,
  commitHeaderInitial,
  type CashVoucherLineFieldState,
} from './fieldHelpers';

export function createInitialCashVoucherFormState(): CashVoucherFormReducerState {
  const headerModel = defaultCashVoucherHeader();
  return {
    header: initHeaderFields(headerModel),
    lines: [initLineFields(emptyCashVoucherLine(), newLineId())],
    meta: {
      status: 'Draft',
      savedSnapshot: null,
      fieldErrors: {},
      generalErrors: [],
    },
    formMode: FormMode.Edit,
  };
}

function mapLineIndex(lines: CashVoucherLineFieldState[], lineId: string): number {
  return lines.findIndex(l => l.lineId === lineId);
}

export function cashVoucherFormReducer(
  state: CashVoucherFormReducerState,
  action: CashVoucherFormAction,
): CashVoucherFormReducerState {
  switch (action.type) {
    case 'SET_HEADER': {
      const displayOnly = CASH_VOUCHER_DISPLAY_ONLY_HEADER_KEYS.includes(action.key);
      return {
        ...state,
        header: {
          ...state.header,
          [action.key]: setFieldValue(state.header[action.key], action.value, displayOnly),
        },
      };
    }
    case 'SET_HEADER_ERROR':
      return {
        ...state,
        header: {
          ...state.header,
          [action.key]: setFieldError(state.header[action.key], action.error),
        },
      };
    case 'SET_LINE': {
      const idx = mapLineIndex(state.lines, action.lineId);
      if (idx < 0) return state;
      const line = state.lines[idx];
      const field = line.fields[action.key as keyof typeof line.fields];
      const displayOnly = action.key === 'accountName' || action.key === 'customerName';
      const nextField = setFieldValue(field, action.value, displayOnly);
      const nextLines = [...state.lines];
      nextLines[idx] = {
        ...line,
        fields: { ...line.fields, [action.key]: nextField },
      };
      return { ...state, lines: nextLines };
    }
    case 'SET_LINES':
      return { ...state, lines: action.lines };
    case 'ADD_LINE':
      return {
        ...state,
        lines: [...state.lines, initLineFields(emptyCashVoucherLine(), newLineId())],
      };
    case 'INSERT_LINE_AFTER': {
      const insertAt = Math.min(action.afterIndex + 1, state.lines.length);
      const newLine = initLineFields(action.model, action.lineId);
      const next = [...state.lines];
      next.splice(insertAt, 0, newLine);
      return { ...state, lines: next };
    }
    case 'REMOVE_LINE':
      if (state.lines.length <= 1) return state;
      return { ...state, lines: state.lines.filter((_, i) => i !== action.index) };
    case 'INIT_HEADER_LINES':
      return { ...state, header: action.header, lines: action.lines };
    case 'COMMIT_INITIAL':
      return {
        ...state,
        header: commitHeaderInitial(state.header),
        lines: state.lines.map(line => {
          const fields = { ...line.fields };
          (Object.keys(fields) as (keyof typeof fields)[]).forEach(key => {
            const f = fields[key];
            const displayOnly = key === 'accountName' || key === 'customerName';
            fields[key] = {
              ...f,
              initialValue: f.value,
              isChanged: displayOnly ? false : false,
              error: undefined,
            };
          });
          return { ...line, fields };
        }),
      };
    case 'SET_FIELD_ERRORS':
      return {
        ...state,
        meta: {
          ...state.meta,
          fieldErrors: action.fieldErrors,
          generalErrors: action.generalErrors ?? state.meta.generalErrors,
        },
      };
    case 'CLEAR_VALIDATION':
      return {
        ...state,
        meta: { ...state.meta, fieldErrors: {}, generalErrors: [] },
        header: (Object.keys(state.header) as (keyof typeof state.header)[]).reduce(
          (h, key) => {
            h[key] = setFieldError(state.header[key], undefined);
            return h;
          },
          { ...state.header },
        ),
      };
    case 'SET_META':
      return { ...state, meta: { ...state.meta, ...action.patch } };
    case 'SET_FORM_MODE':
      return { ...state, formMode: action.formMode };
    case 'RESET_EMPTY': {
      const fresh = createInitialCashVoucherFormState();
      return { ...fresh, formMode: state.formMode };
    }
    default:
      return state;
  }
}
